#!/usr/bin/env python3
"""Aligned greedy-target extraction for the XL dataset.

The frozen mamba SSM context encodes what MAMBA would say next, not what the corpus says
next — so the maximally-ALIGNED continuation target is mamba's own greedy K=8 tokens (this
is the target that carried the STAGE-1 4.38x signal at N=251). This script REUSES the
already-cached XL contexts (real_context_dataset_xl.npz) and only fetches, per prompt, the
frozen model's greedy 8-token continuation from the canary /generate endpoint (ONE call,
max_new_tokens=8), then writes real_context_dataset_xl_greedy.npz (same contexts + greedy
targets). Parallel + incrementally cached (resumable).
"""
import base64
import json
import os
import threading
import time

import numpy as np

_HERE = os.path.dirname(os.path.abspath(__file__))
XL_NPZ = os.path.join(_HERE, "real_context_dataset_xl.npz")
XL_META = os.path.join(_HERE, "real_context_dataset_xl.meta.json")
OUT_NPZ = os.path.join(_HERE, "real_context_dataset_xl_greedy.npz")
OUT_META = os.path.join(_HERE, "real_context_dataset_xl_greedy.meta.json")
CACHE = os.path.join(
    "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/"
    "dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad", "mctx_xl_greedy_cache.jsonl")
GEN_URL = "https://mctx---gnosis-openai-mesh-6ptd7xm6fq-uc.a.run.app/generate"
K = 8


def main(workers=12):
    import requests
    from concurrent.futures import ThreadPoolExecutor

    with open(XL_META) as f:
        meta = json.load(f)
    prompt_ids = meta["prompt_ids"]
    n = len(prompt_ids)
    print(f"[greedy] {n} prompts to fetch greedy K={K} targets", flush=True)

    done = {}
    if os.path.exists(CACHE):
        with open(CACHE) as f:
            for line in f:
                try:
                    r = json.loads(line)
                    done[r["i"]] = r["greedy"]
                except Exception:  # noqa: BLE001
                    pass
        print(f"[resume] {len(done)} already cached", flush=True)

    sess = requests.Session()
    sess.headers.update({"User-Agent": "Mozilla/5.0", "Content-Type": "application/json"})
    lock = threading.Lock()
    cnt = {"n": 0, "fail": 0}
    cache = open(CACHE, "a")
    todo = [i for i in range(n) if i not in done]

    def work(i):
        body = {"tokens": prompt_ids[i], "max_new_tokens": K}
        for attempt in range(18):
            try:
                r = sess.post(GEN_URL, json=body, timeout=120)
                if r.status_code == 200:
                    g = r.json()["generated_tokens"][:K]
                    if len(g) < K:
                        g = g + [g[-1] if g else 0] * (K - len(g))
                    with lock:
                        cache.write(json.dumps({"i": i, "greedy": g}) + "\n")
                        cache.flush()
                        cnt["n"] += 1
                        if cnt["n"] % 200 == 0:
                            print(f"  [{cnt['n']}/{len(todo)}] (fail={cnt['fail']})", flush=True)
                    return
                time.sleep(2 + attempt * 2)
            except Exception:  # noqa: BLE001
                time.sleep(3 + attempt * 2)
        with lock:
            cnt["fail"] += 1

    t0 = time.time()
    with ThreadPoolExecutor(max_workers=workers) as ex:
        list(ex.map(work, todo))
    cache.close()
    print(f"[greedy] done: {cnt['n']} new, {cnt['fail']} failed, {time.time()-t0:.0f}s", flush=True)

    # Assemble: reuse XL contexts, swap greedy targets.
    greedy = {}
    with open(CACHE) as f:
        for line in f:
            try:
                r = json.loads(line)
                greedy[r["i"]] = r["greedy"]
            except Exception:  # noqa: BLE001
                pass
    idx = sorted(greedy.keys())
    z = np.load(XL_NPZ)
    per = z["per_layer_hidden"][idx]
    ssm = z["ssm_state"][idx]
    fin = z["final_hidden"][idx]
    tgt = np.array([greedy[i] for i in idx], dtype=np.int64)
    np.savez_compressed(OUT_NPZ, per_layer_hidden=per, ssm_state=ssm,
                        final_hidden=fin, target_ids=tgt)
    m = dict(meta)
    m["target_kind"] = "mamba-greedy-continuation"
    m["prompts"] = [meta["prompts"][i] for i in idx]
    m["prompt_ids"] = [meta["prompt_ids"][i] for i in idx]
    m["target_ids"] = tgt.tolist()
    m["n"] = len(idx)
    with open(OUT_META, "w") as f:
        json.dump(m, f)
    sz = os.path.getsize(OUT_NPZ) / 1e6
    print(f"assembled -> {OUT_NPZ} ({sz:.1f} MB, n={len(idx)}) + {OUT_META}", flush=True)


if __name__ == "__main__":
    main()
